import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './ChatbotInterface.css';

const ChatbotInterface = () => {
    const [messages, setMessages] = useState([]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const [mode, setMode] = useState('hybrid');
    const messagesEndRef = useRef(null);

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const sendMessage = async () => {
        if (!input.trim()) return;

        const userMessage = input;
        setInput('');
        setMessages(prev => [...prev, { type: 'user', text: userMessage }]);
        
        setLoading(true);

        try {
            const response = await axios.post('/api/chatbot/ask', {
                question: userMessage,
                mode: mode
            }, {
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('token')}`
                }
            });

            if (response.data.success) {
                setMessages(prev => [...prev, { 
                    type: 'bot', 
                    text: response.data.answer 
                }]);
            } else {
                setMessages(prev => [...prev, { 
                    type: 'bot', 
                    text: 'Sorry, I encountered an error. Please try again.' 
                }]);
            }
        } catch (error) {
            console.error('Chatbot error:', error);
            setMessages(prev => [...prev, { 
                type: 'bot', 
                text: 'Connection error. Please check your internet and try again.' 
            }]);
        } finally {
            setLoading(false);
        }
    };

    const clearHistory = async () => {
        try {
            await axios.post('/api/chatbot/clear-history');
            setMessages([]);
        } catch (error) {
            console.error('Clear history error:', error);
        }
    };

    const handleKeyPress = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            sendMessage();
        }
    };

    const suggestQuestions = [
        "What's my total fee for this semester?",
        "Show my attendance in current courses",
        "What are my grades this semester?",
        "What's my class schedule for today?",
        "Do I have any pending assignments?",
        "What's my GPA and academic progress?"
    ];

    return (
        <div className="chatbot-container">
            <div className="chatbot-header">
                <h3>🎓 University AI Assistant</h3>
                <div className="mode-selector">
                    <select value={mode} onChange={(e) => setMode(e.target.value)}>
                        <option value="hybrid">Smart Mode</option>
                        <option value="pure">Pure AI Mode</option>
                        <option value="function">Function Mode</option>
                    </select>
                    <button onClick={clearHistory} className="clear-btn">Clear History</button>
                </div>
            </div>

            <div className="chat-messages">
                {messages.length === 0 ? (
                    <div className="welcome-message">
                        <p>Hello! I'm your AI assistant. I can help you with:</p>
                        <ul>
                            <li>💰 Fees and payments</li>
                            <li>📊 Grades and results</li>
                            <li>📅 Attendance records</li>
                            <li>🏫 Class schedule</li>
                            <li>📚 Course information</li>
                            <li>👨‍🏫 Teacher details</li>
                            <li>📝 Assignments and tasks</li>
                        </ul>
                        
                        <div className="suggestions">
                            <p>Try asking:</p>
                            {suggestQuestions.map((question, index) => (
                                <button 
                                    key={index}
                                    className="suggestion-btn"
                                    onClick={() => setInput(question)}
                                >
                                    {question}
                                </button>
                            ))}
                        </div>
                    </div>
                ) : (
                    messages.map((message, index) => (
                        <div key={index} className={`message ${message.type}`}>
                            <div className="message-content">
                                {message.text.split('\n').map((line, i) => (
                                    <p key={i}>{line}</p>
                                ))}
                            </div>
                        </div>
                    ))
                )}
                {loading && (
                    <div className="message bot">
                        <div className="message-content">
                            <div className="typing-indicator">
                                <span></span>
                                <span></span>
                                <span></span>
                            </div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            <div className="chat-input-container">
                <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Ask me anything about your academic information..."
                    rows="2"
                    disabled={loading}
                />
                <button 
                    onClick={sendMessage} 
                    disabled={loading || !input.trim()}
                    className="send-btn"
                >
                    {loading ? 'Processing...' : 'Send'}
                </button>
            </div>
        </div>
    );
};

export default ChatbotInterface;
